import { describe, it, expect } from 'bun:test';
import {
  isSettled,
  voidIsEmpty,
  voidBackpressure,
  processEntry,
  voluntaryCost,
  involuntaryCost,
  breakEvenRound,
  checkVoluntaryDominance,
  kiVoidSignal,
  kiEnvironmentalSignal,
  isVoidDominated,
  verifyVoidReading,
  isFullyIntegrated,
  diagnoseVoidIntegration,
  type VoidLedger,
} from './void-integration';
import type { KiChannels, CoverSpaceState } from './rumination-topology';

// ---------------------------------------------------------------------------
// Part I: The Void Ledger
// ---------------------------------------------------------------------------

describe('VoidLedger', () => {
  const settledDeep: VoidLedger = { processed: 50, unprocessed: 0, totalCapacity: 50 };
  const empty: VoidLedger = { processed: 0, unprocessed: 0, totalCapacity: 100 };
  const pressured: VoidLedger = { processed: 3, unprocessed: 7, totalCapacity: 10 };

  it('settled void: zero unprocessed', () => {
    expect(isSettled(settledDeep)).toBe(true);
  });

  it('settled ≠ empty: deep history with zero backpressure', () => {
    expect(isSettled(settledDeep)).toBe(true);
    expect(voidIsEmpty(settledDeep)).toBe(false);
  });

  it('empty implies settled', () => {
    expect(voidIsEmpty(empty)).toBe(true);
    expect(isSettled(empty)).toBe(true);
  });

  it('pressured void is not settled', () => {
    expect(isSettled(pressured)).toBe(false);
    expect(voidBackpressure(pressured)).toBe(7);
  });

  it('processEntry moves one entry from unprocessed to processed', () => {
    const after = processEntry(pressured);
    expect(after.processed).toBe(4);
    expect(after.unprocessed).toBe(6);
    expect(after.totalCapacity).toBe(10);
  });

  it('processEntry conserves total', () => {
    const before = pressured;
    const after = processEntry(before);
    expect(before.processed + before.unprocessed).toBe(
      after.processed + after.unprocessed
    );
  });

  it('processEntry reduces backpressure', () => {
    expect(voidBackpressure(processEntry(pressured))).toBeLessThan(
      voidBackpressure(pressured)
    );
  });

  it('repeated processing settles the void', () => {
    let v = pressured;
    while (!isSettled(v)) {
      v = processEntry(v);
    }
    expect(isSettled(v)).toBe(true);
    expect(v.processed).toBe(10);
    expect(v.unprocessed).toBe(0);
  });

  it('settled void at every depth', () => {
    for (const N of [0, 1, 10, 100, 1000]) {
      const v: VoidLedger = { processed: N, unprocessed: 0, totalCapacity: N };
      expect(isSettled(v)).toBe(true);
      expect(v.processed).toBe(N);
    }
  });
});

// ---------------------------------------------------------------------------
// Part II: Voluntary vs Involuntary
// ---------------------------------------------------------------------------

describe('Voluntary vs Involuntary Void Entry', () => {
  it('voluntary cost = spike cost', () => {
    expect(voluntaryCost(3)).toBe(3);
  });

  it('involuntary cost = rounds * phantom + trauma', () => {
    expect(involuntaryCost(2, 5, 1)).toBe(11);
  });

  it('voluntary dominates after 2 rounds (spike=3, phantom=2)', () => {
    const result = checkVoluntaryDominance(3, 2, 2);
    expect(result.dominates).toBe(true);
    expect(result.vCost).toBe(3);
    expect(result.iCost).toBe(4);
    expect(result.savings).toBe(1);
  });

  it('voluntary does NOT dominate at round 1 (spike=3, phantom=2)', () => {
    const result = checkVoluntaryDominance(3, 2, 1);
    expect(result.dominates).toBe(false);
  });

  it('break-even round exists for any positive phantom', () => {
    expect(breakEvenRound(3, 2)).toBe(3); // ceil(3/2) + 1 = 3
    expect(breakEvenRound(3, 1)).toBe(4); // ceil(3/1) + 1 = 4
    expect(breakEvenRound(0, 1)).toBe(1); // ceil(0/1) + 1 = 1
  });

  it('break-even is Infinity when phantom is 0', () => {
    expect(breakEvenRound(3, 0)).toBe(Infinity);
  });

  it('involuntary cost is unbounded', () => {
    const M = 1_000_000;
    const rounds = M + 1;
    expect(involuntaryCost(1, rounds, 0)).toBeGreaterThan(M);
  });

  it('each round of delay adds exactly phantomPerRound', () => {
    const phantom = 2;
    for (let r = 0; r < 10; r++) {
      expect(involuntaryCost(phantom, r + 1, 0)).toBe(
        involuntaryCost(phantom, r, 0) + phantom
      );
    }
  });

  it('immediate entry is optimal among delayed strategies', () => {
    const spike = 3;
    const phantom = 2;
    for (let delay = 1; delay <= 10; delay++) {
      const immediate = voluntaryCost(spike);
      const delayed = delay * phantom + voluntaryCost(spike);
      expect(immediate).toBeLessThan(delayed);
    }
  });
});

// ---------------------------------------------------------------------------
// Part III: Ki as Void-Boundary Reader
// ---------------------------------------------------------------------------

describe('Ki Void-Boundary Reader', () => {
  const voidDominated: KiChannels = {
    glanceLeak: 4, muscleLeak: 1, scentLeak: 0, energyLeak: 6,
  };
  const envDominated: KiChannels = {
    glanceLeak: 1, muscleLeak: 5, scentLeak: 3, energyLeak: 0,
  };
  const balanced: KiChannels = {
    glanceLeak: 2, muscleLeak: 2, scentLeak: 2, energyLeak: 2,
  };

  it('void signal = energy + glance', () => {
    expect(kiVoidSignal(voidDominated)).toBe(10);
    expect(kiEnvironmentalSignal(voidDominated)).toBe(1);
  });

  it('void-dominated when void signal > environmental', () => {
    expect(isVoidDominated(voidDominated)).toBe(true);
    expect(isVoidDominated(envDominated)).toBe(false);
  });

  it('balanced is not void-dominated', () => {
    expect(isVoidDominated(balanced)).toBe(false);
  });

  it('genuine void reading beats 3-way chance', () => {
    expect(verifyVoidReading(8, 12)).toBe('genuine');  // 24 > 12
  });

  it('illusory void reading fails chance gate', () => {
    expect(verifyVoidReading(3, 12)).toBe('illusory'); // 9 ≤ 12
  });

  it('zero correct is always illusory', () => {
    expect(verifyVoidReading(0, 10)).toBe('illusory');
  });
});

// ---------------------------------------------------------------------------
// Part IV: Integrated State
// ---------------------------------------------------------------------------

describe('IntegratedState', () => {
  it('fully integrated = serene cover + settled void', () => {
    expect(isFullyIntegrated({
      coverSpace: { branches: 1, coherence: 100, rounds: 0, crossings: 0 },
      voidLedger: { processed: 50, unprocessed: 0, totalCapacity: 50 },
    })).toBe(true);
  });

  it('serene cover + pressured void is NOT fully integrated', () => {
    expect(isFullyIntegrated({
      coverSpace: { branches: 1, coherence: 100, rounds: 0, crossings: 0 },
      voidLedger: { processed: 3, unprocessed: 2, totalCapacity: 5 },
    })).toBe(false);
  });

  it('settled void + ruminating cover is NOT fully integrated', () => {
    expect(isFullyIntegrated({
      coverSpace: { branches: 4, coherence: 30, rounds: 10, crossings: 5 },
      voidLedger: { processed: 10, unprocessed: 0, totalCapacity: 10 },
    })).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// Part V: Full Diagnostic
// ---------------------------------------------------------------------------

describe('diagnoseVoidIntegration', () => {
  it('produces full diagnostic for active rumination with void pressure', () => {
    const cs: CoverSpaceState = {
      branches: 4, coherence: 25, rounds: 8, crossings: 5,
    };
    const vl: VoidLedger = {
      processed: 3, unprocessed: 7, totalCapacity: 10,
    };
    const k: KiChannels = {
      glanceLeak: 3, muscleLeak: 0, scentLeak: 1, energyLeak: 7,
    };
    const diag = diagnoseVoidIntegration(cs, vl, k);

    expect(diag.settled).toBe(false);
    expect(diag.empty).toBe(false);
    expect(diag.backpressure).toBe(7);
    expect(diag.stepsToSettle).toBe(7);
    expect(diag.ki.voidDominated).toBe(true);
    expect(diag.ki.disharmony).toBe(true);
    expect(diag.ki.voidSignal).toBe(10);
    expect(diag.ki.environmentalSignal).toBe(1);
    expect(diag.entryAnalysis.dominates).toBe(true); // round 8, phantom 2
    expect(diag.coverSpace.serene).toBe(false);
    expect(diag.coverSpace.ruminating).toBe(true);
    expect(diag.coverSpace.metabolicCost).toBe(20);
    expect(diag.fullyIntegrated).toBe(false);
    expect(diag.totalPathToIntegration).toBe(12); // 5 + 7
  });

  it('produces serene + settled diagnostic for integrated state', () => {
    const cs: CoverSpaceState = {
      branches: 1, coherence: 100, rounds: 0, crossings: 0,
    };
    const vl: VoidLedger = {
      processed: 100, unprocessed: 0, totalCapacity: 100,
    };
    const k: KiChannels = {
      glanceLeak: 0, muscleLeak: 0, scentLeak: 0, energyLeak: 0,
    };
    const diag = diagnoseVoidIntegration(cs, vl, k);

    expect(diag.settled).toBe(true);
    expect(diag.empty).toBe(false); // 100 processed -- deep history
    expect(diag.backpressure).toBe(0);
    expect(diag.ki.voidDominated).toBe(false);
    expect(diag.ki.disharmony).toBe(false);
    expect(diag.coverSpace.serene).toBe(true);
    expect(diag.fullyIntegrated).toBe(true);
    expect(diag.totalPathToIntegration).toBe(0);
  });
});
